    <script>
        $(function () {
            const pickSwiperEl = document.querySelector(".donuts-pick-swiper");

            if (!pickSwiperEl || typeof Swiper === "undefined") {
                return;
            }

            const pickSwiper = new Swiper(".donuts-pick-swiper", {
                loop: true,
                grabCursor: true,
                centeredSlides: true,
                slidesPerView: "auto",
                spaceBetween: 0,
                breakpointsBase: "container",
                effect: "creative",
                creativeEffect: {
                    perspective: false,
                    limitProgress: 3,
                    prev: {
                        translate: ["-30%", "20%", 0],
                        rotate: [0, 0, -40],
                        origin: "bottom"
                    },
                    next: {
                        translate: ["30%", "20%", 0],
                        rotate: [0, 0, 40],
                        origin: "bottom"
                    }
                }
            });
        });
