    // - 위치와 관련된 DB 값 추가 시 수정 필요
    $sql_club_board = " select bo_table, bo_subject, bo_content_head, bo_content_tail
                        from {$g5['board_table']}
                        where gr_id = 'club'
                        and bo_list_level <= '{$member['mb_level']}'
                        and bo_device <> 'mobile' ";
    if (!$is_admin) {
        $sql_club_board .= " and bo_use_cert = '' ";
